const topic = $input.first().json.topic;
const payload = $input.first().json.message;

// homelab/air_quality/{location}/alerts/{type}
const parts = topic.split('/');
const location = parts[2];
const isAlert = parts[3] === 'alerts';
const alertType = parts[4];
const value = parseFloat(payload) || payload;

const alertMessages = {
  co2: {
    warning: `⚠️ CO2 elevated: ${value} ppm — consider ventilation`,
    critical: `🚨 CO2 critical: ${value} ppm — open windows NOW`,
    normal: null
  },
  pm25: {
    warning: `⚠️ PM2.5: ${value} µg/m³ — air quality degraded`,
    normal: null
  }
};

let message = null;
if (isAlert && alertMessages[alertType]) {
  message = alertMessages[alertType][payload];
}

return [{
  json: {
    location,
    isAlert,
    alertType,
    alertLevel: payload,
    value,
    message,
    timestamp: new Date().toISOString(),
    shouldNotify: message !== null
  }
}];
